void solve(int CASE)
{
	int n; cin >> n;
	var s = vector<int>(n + 1);
	var d = vector<int>(n + 1);
	var siz = vector<int>(n + 1);
	fa(i, 1, n)s[i] = i, siz[i] = 1;
	var find = [&](var find, int x)->int {
		if (s[x] == x)return x;
		int r = find(find, s[x]);
		d[x] += d[s[x]];
		return s[x] = r;
		};
	fa(i, 1, n) {
		char op; cin >> op;
		int x, y; cin >> x >> y;
		int e1 = find(find, x), e2 = find(find, y);
		if (op == 'M') {
			if (e1 != e2) {
				s[e2] = e1;
				d[e2] = siz[e1]; // 根据 siz 更新 d[e2]
				siz[e1] += siz[e2];
			}
		}
		else {
			if (e1 != e2)cout << -1 << endl;
			else cout << abs(d[x] - d[y]) - 1 << endl;
		}
	}
	return;
}
